-- ----------------------------
-- Table structure for iot_device_modbus_config
-- ----------------------------
DROP TABLE IF EXISTS `iot_device_modbus_config`;
CREATE TABLE `iot_device_modbus_config`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `device_id` bigint NOT NULL COMMENT '设备编号',
  `product_id` bigint NULL DEFAULT NULL COMMENT '产品编号',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'Modbus 服务器 IP 地址',
  `port` int NOT NULL DEFAULT 502 COMMENT 'Modbus 服务器端口',
  `slave_id` int NOT NULL DEFAULT 1 COMMENT '从站地址',
  `timeout` int NOT NULL DEFAULT 3000 COMMENT '连接超时时间，单位：毫秒',
  `retry_interval` int NOT NULL DEFAULT 1000 COMMENT '重试间隔，单位：毫秒',
  `mode` tinyint NOT NULL DEFAULT 1 COMMENT '工作模式',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态',
  `frame_format` tinyint NOT NULL DEFAULT 1 COMMENT '数据帧格式',
  `creator` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否删除',
  `tenant_id` bigint NOT NULL DEFAULT 0 COMMENT '租户编号',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_device_id`(`device_id` ASC, `deleted` ASC, `tenant_id` ASC) USING BTREE COMMENT '设备编号唯一索引'
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'IoT 设备 Modbus 连接配置表';

-- ----------------------------
-- Records of iot_device_modbus_config
-- ----------------------------
BEGIN;
INSERT INTO `iot_device_modbus_config` (`id`, `device_id`, `product_id`, `ip`, `port`, `slave_id`, `timeout`, `retry_interval`, `mode`, `status`, `frame_format`, `creator`, `create_time`, `updater`, `update_time`, `deleted`, `tenant_id`) VALUES (1, 30, NULL, '127.0.0.1', 5020, 1, 3000, 1000, 1, 0, 1, '1', '2026-01-17 23:25:50', '1', '2026-02-08 12:22:36', b'0', 1), (2, 80, NULL, '', 502, 1, 3000, 10000, 1, 0, 1, '1', '2026-02-08 20:41:04', '1', '2026-02-08 20:45:04', b'0', 1), (3, 81, NULL, '', 502, 1, 3000, 10000, 1, 0, 2, '1', '2026-02-08 21:41:13', '1', '2026-02-14 09:13:06', b'0', 1), (4, 82, NULL, '127.0.0.1', 5020, 1, 3000, 10000, 1, 0, 1, '1', '2026-02-08 21:42:51', '1', '2026-02-08 22:44:55', b'0', 1);
