-- ----------------------------
-- Table structure for iot_device_modbus_point
-- ----------------------------
DROP TABLE IF EXISTS `iot_device_modbus_point`;
CREATE TABLE `iot_device_modbus_point`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `device_id` bigint NOT NULL COMMENT '设备编号',
  `thing_model_id` bigint NOT NULL COMMENT '物模型属性编号',
  `identifier` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '属性标识符',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '属性名称',
  `function_code` tinyint NOT NULL DEFAULT 3 COMMENT 'Modbus 功能码（1-读线圈 2-读离散输入 3-读保持寄存器 4-读输入寄存器）',
  `register_address` int NOT NULL DEFAULT 0 COMMENT '寄存器起始地址',
  `register_count` int NOT NULL DEFAULT 1 COMMENT '寄存器数量',
  `byte_order` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'AB' COMMENT '字节序（AB/BA/ABCD/CDAB/DCBA/BADC）',
  `raw_data_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'INT16' COMMENT '原始数据类型（INT16/UINT16/INT32/UINT32/FLOAT/DOUBLE/BOOLEAN/STRING）',
  `scale` decimal(20, 6) NOT NULL DEFAULT 1.000000 COMMENT '缩放因子',
  `poll_interval` int NOT NULL DEFAULT 5000 COMMENT '轮询间隔，单位：毫秒',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态（0-开启 1-禁用）',
  `creator` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updater` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否删除',
  `tenant_id` bigint NOT NULL DEFAULT 0 COMMENT '租户编号',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_device_thing_model`(`device_id` ASC, `thing_model_id` ASC, `deleted` ASC, `tenant_id` ASC) USING BTREE COMMENT '设备+物模型唯一索引',
  INDEX `idx_device_id`(`device_id` ASC) USING BTREE COMMENT '设备编号索引'
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'IoT 设备 Modbus 点位配置表';

